# Base shapes module - provides abstract base class for geometric shapes

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return self.name

